@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Render the label, control and helper/error as ONE self-contained block so the field
   never splays into a row when dropped in a flex / centered container. Root class is
   variant-aware: Button/Avatar stay inline-flex so they work inside toolbars; Dropzone
   uses flex-col w-full (no items-start) so the zone can stretch to its container. *@
<div class="@RootClass">
@if (Label is not null && !InsideFormField && Variant != FileUploadVariant.Button && Variant != FileUploadVariant.Avatar)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@if (Variant == FileUploadVariant.Button)
{
    <div class="@(Cx.Merge("inline-flex flex-col gap-2", Class))"
         aria-required="@Required.ToString().ToLower()"
         aria-invalid="@EffectiveInvalid.ToString().ToLower()"
         @attributes="AdditionalAttributes">
        <label class="@ButtonLabelCssClass">
            <SvgGlyph Svg="@(LumeoIcons.Upload)" class="h-4 w-4" />
            <span>@(Label ?? L["FileUpload.ChooseFile"])</span>
            <InputFile @key="_inputFileKey" id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy" class="sr-only" OnChange="HandleFileSelected" multiple="@Multiple" accept="@Accept" />
        </label>
        @if (!AutoUpload && _uploadItems.Any(i => i.Status == FileUploadStatus.Pending))
        {
            <button type="button" class="inline-flex items-center gap-1.5 rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                    @onclick="StartUploadAsync">
                <SvgGlyph Svg="@(LumeoIcons.Upload)" class="h-3.5 w-3.5" />
                Upload
            </button>
        }
        @if (_globalErrorMessage is not null)
        {
            <p class="text-xs text-destructive">@_globalErrorMessage</p>
        }
        @if (ShowFileList && _uploadItems.Count > 0)
        {
            <div class="flex flex-col gap-1">
                @foreach (var item in _uploadItems)
                {
                    <div @key="item.Id">
                    @if (FileTemplate is not null)
                    {
                        @FileTemplate(item.File)
                    }
                    else
                    {
                        @RenderFileItem(item)
                    }
                    </div>
                }
            </div>
        }
        @if (!InsideFormField)
        {
            @if (EffectiveInvalid && ErrorText is not null)
            {
                <p class="text-xs text-destructive">@ErrorText</p>
            }
            else if (HelperText is not null)
            {
                <p class="text-xs text-muted-foreground">@HelperText</p>
            }
        }
    </div>
}
else if (Variant == FileUploadVariant.Avatar)
{
    <div class="@(Cx.Merge("inline-flex flex-col items-center gap-2", Class))"
         aria-required="@Required.ToString().ToLower()"
         aria-invalid="@EffectiveInvalid.ToString().ToLower()"
         @attributes="AdditionalAttributes">
        <label class="flex h-20 w-20 cursor-pointer items-center justify-center overflow-hidden rounded-full border-2 border-dashed border-input bg-muted transition-colors hover:border-primary hover:bg-muted/80">
            @if (ShowThumbnails && _thumbnailUrl is not null)
            {
                <img src="@_thumbnailUrl" alt="Avatar preview" class="h-full w-full object-cover" />
            }
            else
            {
                <SvgGlyph Svg="@(LumeoIcons.User)" class="h-8 w-8 text-muted-foreground" />
            }
            <InputFile @key="_inputFileKey" id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy" class="sr-only" OnChange="HandleFileSelected" multiple="false" accept="@(Accept ?? "image/*")" />
        </label>
        @if (_globalErrorMessage is not null)
        {
            <p class="text-xs text-destructive">@_globalErrorMessage</p>
        }
        @if (!InsideFormField)
        {
            @if (EffectiveInvalid && ErrorText is not null)
            {
                <p class="text-xs text-destructive">@ErrorText</p>
            }
            else if (HelperText is not null)
            {
                <p class="text-xs text-muted-foreground">@HelperText</p>
            }
        }
    </div>
}
else
{
    <div class="@(Cx.Merge("flex flex-col gap-2", Class))" @attributes="AdditionalAttributes">
        <label class="@DropzoneCssClass"
               aria-required="@Required.ToString().ToLower()"
               aria-invalid="@EffectiveInvalid.ToString().ToLower()"
               @ondragenter="HandleDragEnter"
               @ondragleave="HandleDragLeave"
               @ondragover:preventDefault="true"
               @ondrop="HandleDrop">
            <div class="flex flex-col items-center justify-center gap-2 py-4">
                <SvgGlyph Svg="@(LumeoIcons.Upload)" class="h-8 w-8 text-muted-foreground" />
                <div class="text-center">
                    <p class="text-sm font-medium">
                        @if (Label is not null)
                        {
                            @Label
                        }
                        else
                        {
                            <span>@L["FileUpload.ClickToUpload"]</span>
                        }
                    </p>
                    @if (Description is not null)
                    {
                        <p class="text-xs text-muted-foreground mt-1">@Description</p>
                    }
                </div>
            </div>
            @* Stretched invisibly over the whole dropzone: native drag&drop onto a
               file input adds the dropped files and fires OnChange (no JS needed),
               and clicking anywhere in the zone opens the browse dialog. *@
            <InputFile @key="_inputFileKey" id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy" class="absolute inset-0 h-full w-full cursor-pointer opacity-0" OnChange="HandleFileSelected" multiple="@Multiple" accept="@Accept" />
        </label>
        @if (_globalErrorMessage is not null)
        {
            <p class="text-xs text-destructive">@_globalErrorMessage</p>
        }
        @* Legacy global progress bar — kept for back-compat *@
        @if (ShowProgress && OnUpload is null)
        {
            <div class="h-2 w-full overflow-hidden rounded-[calc(var(--radius)*2)] bg-muted">
                <div class="h-full rounded-[calc(var(--radius)*2)] bg-primary transition-all duration-300"
                     style="width: @(Math.Clamp(Progress, 0, 100))%"></div>
            </div>
        }
        @if (!AutoUpload && _uploadItems.Any(i => i.Status == FileUploadStatus.Pending))
        {
            <button type="button" class="inline-flex items-center gap-1.5 rounded-md bg-primary px-3 py-1.5 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 self-start"
                    @onclick="StartUploadAsync">
                <SvgGlyph Svg="@(LumeoIcons.Upload)" class="h-4 w-4" />
                Upload @(_uploadItems.Count(i => i.Status == FileUploadStatus.Pending)) file@(_uploadItems.Count(i => i.Status == FileUploadStatus.Pending) != 1 ? "s" : "")
            </button>
        }
        @if (ShowFileList && _uploadItems.Count > 0)
        {
            <div class="flex flex-col gap-2">
                @foreach (var item in _uploadItems)
                {
                    <div @key="item.Id">
                    @if (FileTemplate is not null)
                    {
                        @FileTemplate(item.File)
                    }
                    else
                    {
                        @RenderFileItem(item)
                    }
                    </div>
                }
            </div>
        }
        @if (!InsideFormField)
        {
            @if (EffectiveInvalid && ErrorText is not null)
            {
                <p class="text-xs text-destructive">@ErrorText</p>
            }
            else if (HelperText is not null)
            {
                <p class="text-xs text-muted-foreground">@HelperText</p>
            }
        }
    </div>
}
</div>

@code {
    // ── Form-field integration ───────────────────────────────────────────────
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    /// <summary>Marks the field as required, setting <c>aria-required</c> and (outside a <c>FormField</c>, on the Dropzone/generic label) appending a destructive-colored asterisk to the label.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid/error visual state (destructive border on the dropzone, destructive helper text) and <c>aria-invalid</c>, independent of the ambient <c>FormField</c>'s validation state.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error message shown below the control (outside a <c>FormField</c>) when <see cref="Invalid"/> is set. Takes precedence over <see cref="HelperText"/>.</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the control (outside a <c>FormField</c>) when there is no error to display.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Field name for form-field integration. Not currently rendered onto the underlying <c>&lt;InputFile&gt;</c> element.</summary>
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // ── Visual / selection params ────────────────────────────────────────────
    /// <summary>Label text. Rendered above the control on the Dropzone/Avatar variants when outside a <c>FormField</c>, or as the Dropzone's headline / the Button variant's caption when set.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>Secondary helper text shown below the headline on the Dropzone variant (e.g. accepted types or size limits).</summary>
    [Parameter] public string? Description { get; set; }
    /// <summary>Allows selecting more than one file at once. Ignored by the Avatar variant, which is always single-file.</summary>
    [Parameter] public bool Multiple { get; set; }
    /// <summary>The native <c>accept</c> attribute value (e.g. <c>"image/*"</c> or <c>".pdf,.docx"</c>), used both to filter the OS file picker and to validate dropped/selected files client-side.</summary>
    [Parameter] public string? Accept { get; set; }
    /// <summary>Maximum size in bytes allowed per file; larger files are rejected with <see cref="MaxFileSizeError"/> (or a localized default). Default 10 MB.</summary>
    [Parameter] public long MaxFileSize { get; set; } = 10 * 1024 * 1024;
    /// <summary>Maximum number of files (counting non-failed/cancelled existing items) allowed in the selection at once; exceeding it rejects the whole new batch with <see cref="MaxFilesError"/>. Default 10.</summary>
    [Parameter] public int MaxFiles { get; set; } = 10;
    /// <summary>Renders an inline image preview (data URI) for image files, on both the file-list rows and the Avatar variant's picker.</summary>
    [Parameter] public bool ShowThumbnails { get; set; }
    /// <summary>Custom render fragment for each file-list row, receiving the underlying <see cref="IBrowserFile"/>. Falls back to the built-in row (icon/thumbnail, name, size, status, progress, actions) when unset.</summary>
    [Parameter] public RenderFragment<IBrowserFile>? FileTemplate { get; set; }

    /// <summary>
    /// When <c>true</c> (default), renders the internal file card list after selection.
    /// Set to <c>false</c> for immediate-upload flows where the app renders its own file
    /// list — the internal card with the remove-X will no longer linger after the upload
    /// completes. Selection and upload events (<see cref="OnFilesSelected"/>,
    /// <see cref="OnUpload"/>, <see cref="OnFileUploaded"/>) still fire normally regardless
    /// of this setting. Pair with <see cref="Reset"/> via <c>@@ref</c> to clear state and
    /// allow the same file to be re-picked.
    /// </summary>
    [Parameter] public bool ShowFileList { get; set; } = true;

    /// <summary>Visual presentation: <see cref="FileUploadVariant.Dropzone"/> (drag-and-drop area, default), <see cref="FileUploadVariant.Button"/> (compact inline trigger button), or <see cref="FileUploadVariant.Avatar"/> (single circular image picker).</summary>
    [Parameter] public FileUploadVariant Variant { get; set; } = FileUploadVariant.Dropzone;

    /// <summary>
    /// Size of the trigger when <c>Variant="Button"</c>. Mirrors
    /// <see cref="Lumeo.Button.ButtonSize"/> so a button-variant FileUpload can
    /// match neighbouring buttons in toolbars or compact forms. Has no visual
    /// effect on <c>Dropzone</c> or <c>Avatar</c> variants today.
    /// </summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    // ── Legacy back-compat progress params ──────────────────────────────────
    /// <summary>Legacy: shows a single global progress bar driven by <see cref="Progress"/>. Ignored once <see cref="OnUpload"/> is set, since per-file progress is tracked automatically.</summary>
    [Parameter] public bool ShowProgress { get; set; }

    /// <remarks>Obsolete when <see cref="OnUpload"/> is set — per-file progress is tracked automatically via <see cref="FileUploadItem.ProgressPercent"/>.</remarks>
    [Parameter] public int Progress { get; set; }

    // ── Upload pipeline params ───────────────────────────────────────────────
    /// <summary>
    /// Consumer-supplied upload handler. Called once per file after selection
    /// (or after explicit <c>StartUploadAsync</c> if <see cref="AutoUpload"/> is false).
    /// Receives the item, an <see cref="IProgress{T}"/> for reporting percent 0-100,
    /// and a <see cref="CancellationToken"/> that fires if the user clicks Cancel.
    /// Should return the server-assigned URL/id on success, or throw/return null on failure.
    /// </summary>
    [Parameter] public Func<FileUploadItem, IProgress<int>, CancellationToken, Task<string?>>? OnUpload { get; set; }

    /// <summary>
    /// When <c>true</c> (default), uploads begin immediately after files are selected.
    /// When <c>false</c>, the user must click the Upload button to start.
    /// Requires <see cref="OnUpload"/> to be set.
    /// </summary>
    [Parameter] public bool AutoUpload { get; set; } = true;

    /// <summary>Maximum number of <see cref="OnUpload"/> calls running simultaneously.</summary>
    [Parameter] public int MaxConcurrentUploads { get; set; } = 3;

    /// <summary>
    /// Optional chunk size hint (bytes) for consumers that want to implement
    /// chunked/resumable upload inside their <see cref="OnUpload"/> handler.
    /// The component passes this value through <see cref="FileUploadItem.ChunkSize"/>
    /// but does NOT implement chunking itself.
    /// </summary>
    [Parameter] public long? ChunkSize { get; set; }

    // ── Validation error message overrides ──────────────────────────────────
    /// <summary>Overrides the default localized "exceeds max size" message shown when a file is rejected for being larger than <see cref="MaxFileSize"/>.</summary>
    [Parameter] public string? MaxFileSizeError { get; set; }
    /// <summary>Overrides the default "Maximum N files allowed" message shown when a selection would exceed <see cref="MaxFiles"/>.</summary>
    [Parameter] public string? MaxFilesError { get; set; }
    /// <summary>Overrides the default "unsupported file type" message shown when a file doesn't match <see cref="Accept"/>.</summary>
    [Parameter] public string? FileTypeError { get; set; }

    // ── Events ───────────────────────────────────────────────────────────────
    /// <summary>Fires when files are selected (raw args, kept for back-compat).</summary>
    [Parameter] public EventCallback<InputFileChangeEventArgs> OnFilesSelected { get; set; }

    /// <summary>Fires each time a file upload succeeds.</summary>
    [Parameter] public EventCallback<FileUploadItem> OnFileUploaded { get; set; }

    /// <summary>Fires when all queued uploads have finished (succeeded, failed, or cancelled).</summary>
    [Parameter] public EventCallback<IReadOnlyList<FileUploadItem>> OnAllUploaded { get; set; }

    /// <summary>Fires each time a file upload fails.</summary>
    [Parameter] public EventCallback<FileUploadItem> OnFileFailed { get; set; }

    /// <summary>Fires when a file is removed from the list.</summary>
    [Parameter] public EventCallback<FileUploadItem> OnFileRemoved { get; set; }

    /// <summary>Fires when a file is rejected due to type/size/count constraints.</summary>
    [Parameter] public EventCallback<(IBrowserFile File, string Reason)> OnFileRejected { get; set; }

    // ── CSS / additional attrs ───────────────────────────────────────────────
    /// <summary>Additional CSS classes merged onto the variant-specific root element (the dropzone/button/avatar wrapper).</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the variant-specific root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // ── Enums ────────────────────────────────────────────────────────────────
    public enum FileUploadVariant { Dropzone, Button, Avatar }

    /// <summary>Per-file upload state tracked internally and exposed via events.</summary>
    public class FileUploadItem
    {
        public string Id { get; init; } = Guid.NewGuid().ToString("N");
        public IBrowserFile File { get; init; } = default!;
        public string Name { get; init; } = string.Empty;
        public long Size { get; init; }
        public FileUploadStatus Status { get; set; } = FileUploadStatus.Pending;
        public int ProgressPercent { get; set; }
        public string? ErrorMessage { get; set; }
        /// <summary>
        /// True when this item is a pre-upload validation rejection (size/type/count)
        /// rather than a failure of the <see cref="FileUpload.OnUpload"/> handler.
        /// Validation rejections are not retryable — re-running the upload would just
        /// hit the same constraint — so the Retry affordance is gated on this flag
        /// instead of brittle, localization-dependent error-message text matching.
        /// </summary>
        public bool IsValidationRejection { get; init; }
        /// <summary>Server-returned URL or id after a successful upload.</summary>
        public string? Url { get; set; }
        /// <summary>Chunk-size hint (bytes) from <see cref="FileUpload.ChunkSize"/>. Zero if not configured.</summary>
        public long ChunkSize { get; init; }
    }

    public enum FileUploadStatus { Pending, Uploading, Succeeded, Failed, Cancelled }

    // ── Internal state ───────────────────────────────────────────────────────
    private bool _isDragOver;
    private int _dragDepth;
    private string? _globalErrorMessage;
    private string? _thumbnailUrl;
    private List<FileUploadItem> _uploadItems = new();
    private Dictionary<string, string> _thumbnailUrls = new();
    // Incremented by Reset() to force each <InputFile> element to remount with a fresh
    // DOM node — the only cross-browser way to clear the browser's file selection so the
    // same file can be re-picked after an immediate upload.
    private int _inputFileKey;
    private readonly Dictionary<string, CancellationTokenSource> _cancellations = new();
    private SemaphoreSlim? _concurrencySemaphore;
    // The MaxConcurrentUploads value the live _concurrencySemaphore was built with.
    // Tracked so a runtime change to MaxConcurrentUploads can rebuild the semaphore
    // (a SemaphoreSlim's count is fixed at construction) instead of being latched
    // forever by the first `??=`.
    private int _concurrencySemaphoreCount;
    private int _currentBatchId;
    // Guards OnAllUploaded against double-firing for the same terminal set while
    // still allowing it to fire once per fresh round of pending items. Reset to
    // false whenever a new pending item is queued (see TerminalState handling).
    private bool _allUploadedFired;
    // Set at the start of DisposeAsync. A consumer's OnUpload Task (and the
    // IProgress<int> it holds) can keep running and reporting progress AFTER the
    // component is torn down — every fire-and-forget InvokeAsync(StateHasChanged)
    // would then dispatch against a disposed renderer and throw
    // ObjectDisposedException. This flag short-circuits those late dispatches.
    private bool _disposed;
    // Cancelled at the very start of DisposeAsync so any task blocked in
    // _concurrencySemaphore.WaitAsync() receives OperationCanceledException and
    // exits without ever acquiring a slot — and therefore without needing to call
    // Release(), which eliminates the semaphore-disposed / over-release race.
    private readonly CancellationTokenSource _disposeCts = new();

    // Dispatches a render only while the component is still alive. Used by the
    // post-await callbacks in the upload pipeline (progress reports, success/fail
    // handlers, terminal check) which can fire after DisposeAsync has run because
    // the consumer's OnUpload Task outlives the component. Swallows the
    // ObjectDisposedException race where disposal happens mid-dispatch.
    private async Task SafeInvokeStateHasChangedAsync()
    {
        if (_disposed) return;
        try
        {
            await InvokeAsync(StateHasChanged);
        }
        catch (ObjectDisposedException) { }
    }

    // Kept for back-compat so existing code that reads _selectedFiles-equivalent still compiles.
    // Exposed as a convenience projection.
    private List<IBrowserFile> _selectedFiles => _uploadItems.Select(i => i.File).ToList();

    // ── CSS helpers ──────────────────────────────────────────────────────────

    // Variant-aware root-wrapper class.
    // • Button / Avatar → inline-flex: renders inline so the component stays in-flow
    //   inside toolbars and doesn't break onto its own block line.
    // • Dropzone        → flex flex-col w-full: vertical stack that stretches to the
    //   container's full width (no items-start shrink-wrapping).
    private string RootClass => Variant switch
    {
        FileUploadVariant.Button => "inline-flex",
        FileUploadVariant.Avatar => "inline-flex",
        _ => "flex flex-col w-full"
    };

    private string ButtonSizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-8 px-3 text-xs",
        Lumeo.Size.Lg => "h-10 px-8 text-sm",
        _ => "h-9 px-4 py-2 text-sm"
    };

    private string ButtonLabelCssClass =>
        $"inline-flex cursor-pointer items-center justify-center gap-2 rounded-md bg-primary {ButtonSizeClasses} font-medium text-primary-foreground transition-colors hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private string DropzoneCssClass => $"relative flex cursor-pointer flex-col items-center justify-center rounded-lg border border-dashed transition-colors {(_isDragOver ? "border-primary bg-primary/5" : EffectiveInvalid ? "border-destructive bg-destructive/5" : _globalErrorMessage is not null ? "border-destructive bg-destructive/5" : "border-input bg-background hover:border-primary hover:bg-muted")} px-6".Trim();

    // ── Drag handlers ────────────────────────────────────────────────────────
    // The dropped files themselves are handled natively: the <InputFile> is
    // stretched invisibly over the whole dropzone, so the browser populates it
    // on drop and OnChange fires. These handlers only drive the visual
    // drag-over highlight.
    //
    // NOTE: do NOT add @ondrop:preventDefault on the label (or any ancestor) —
    // Blazor applies the flag to events bubbling up from descendants, and a
    // cancelled drop stops the browser from populating the InputFile.
    //
    // _dragDepth counts dragenter/dragleave pairs because the spec fires
    // dragenter at the new target BEFORE dragleave at the old one when moving
    // between nested elements — a plain bool would flicker off while the
    // pointer is still inside the zone.
    private void HandleDragEnter(DragEventArgs e)
    {
        _dragDepth++;
        _isDragOver = true;
    }

    private void HandleDragLeave(DragEventArgs e)
    {
        if (--_dragDepth <= 0)
        {
            _dragDepth = 0;
            _isDragOver = false;
        }
    }

    private void HandleDrop(DragEventArgs e)
    {
        _dragDepth = 0;
        _isDragOver = false;
    }

    // ── File selected ────────────────────────────────────────────────────────
    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        _globalErrorMessage = null;

        // Avatar variant is a single-slot picker that only ever shows _thumbnailUrl —
        // the file list is never rendered. Appending instead of replacing left stale
        // hidden items that still counted against MaxFiles, so after enough re-picks
        // the next selection spuriously tripped the "Maximum N files" rejection even
        // though only one avatar is ever visible. Clear the prior slot (items,
        // thumbnails, in-flight cancellations) so a re-pick truly replaces it.
        if (Variant == FileUploadVariant.Avatar && _uploadItems.Count > 0)
        {
            foreach (var prior in _uploadItems)
            {
                if (_cancellations.TryGetValue(prior.Id, out var priorCts))
                {
                    try { priorCts.Cancel(); } catch (ObjectDisposedException) { }
                    _cancellations.Remove(prior.Id);
                }
                _thumbnailUrls.Remove(prior.Id);
            }
            _uploadItems.Clear();
        }

        // Pass the actual selection count: GetMultipleFiles THROWS when the user
        // picks more files than the argument allows — capping at MaxFiles + 1
        // crashed instead of surfacing the MaxFiles error below.
        var candidates = Multiple ? e.GetMultipleFiles(Math.Max(e.FileCount, 1)).ToList() : new List<IBrowserFile> { e.File };

        // Count check against existing non-failed items
        var existing = _uploadItems.Count(i => i.Status != FileUploadStatus.Failed && i.Status != FileUploadStatus.Cancelled);
        if (existing + candidates.Count > MaxFiles)
        {
            var reason = MaxFilesError ?? $"Maximum {MaxFiles} file{(MaxFiles != 1 ? "s" : "")} allowed.";
            _globalErrorMessage = reason;
            // Still add them as rejected items
            foreach (var f in candidates)
            {
                var rejected = new FileUploadItem { File = f, Name = f.Name, Size = f.Size, Status = FileUploadStatus.Failed, ErrorMessage = reason, ChunkSize = ChunkSize ?? 0, IsValidationRejection = true };
                _uploadItems.Add(rejected);
                await OnFileRejected.InvokeAsync((f, reason));
            }
            await OnFilesSelected.InvokeAsync(e);
            return;
        }

        var validFiles = new List<IBrowserFile>();

        foreach (var file in candidates)
        {
            // Size validation
            if (file.Size > MaxFileSize)
            {
                var reason = MaxFileSizeError ?? L["FileUpload.ExceedsMaxSize", file.Name, FormatSize(MaxFileSize)];
                var rejected = new FileUploadItem { File = file, Name = file.Name, Size = file.Size, Status = FileUploadStatus.Failed, ErrorMessage = reason, ChunkSize = ChunkSize ?? 0, IsValidationRejection = true };
                _uploadItems.Add(rejected);
                await OnFileRejected.InvokeAsync((file, reason));
                continue;
            }

            // Accept/type validation
            if (!string.IsNullOrWhiteSpace(Accept) && !IsAccepted(file, Accept))
            {
                var reason = FileTypeError ?? $"File \"{file.Name}\" has an unsupported file type.";
                var rejected = new FileUploadItem { File = file, Name = file.Name, Size = file.Size, Status = FileUploadStatus.Failed, ErrorMessage = reason, ChunkSize = ChunkSize ?? 0, IsValidationRejection = true };
                _uploadItems.Add(rejected);
                await OnFileRejected.InvokeAsync((file, reason));
                continue;
            }

            validFiles.Add(file);
            var item = new FileUploadItem { File = file, Name = file.Name, Size = file.Size, Status = FileUploadStatus.Pending, ChunkSize = ChunkSize ?? 0 };
            _uploadItems.Add(item);
            // A fresh pending item means OnAllUploaded must be allowed to fire
            // again once this new work reaches a terminal state.
            _allUploadedFired = false;
        }

        // Thumbnails for avatar variant
        if (ShowThumbnails && Variant == FileUploadVariant.Avatar && validFiles.Count > 0 && IsImageFile(validFiles[0]))
        {
            try
            {
                var stream = validFiles[0].OpenReadStream(MaxFileSize);
                using var ms = new MemoryStream();
                await stream.CopyToAsync(ms);
                _thumbnailUrl = $"data:{validFiles[0].ContentType};base64,{Convert.ToBase64String(ms.ToArray())}";
            }
            catch { _thumbnailUrl = null; }
        }

        // Thumbnails for dropzone variant. Keyed by the per-item Id (not file.Name)
        // so two selected files with the SAME name don't collide — name-keying made
        // the second write clobber the first's thumbnail and removing either row
        // wiped both. Match each just-added pending item to its source file by
        // reference so the dictionary key is the stable item.Id.
        if (ShowThumbnails && Variant == FileUploadVariant.Dropzone)
        {
            foreach (var file in validFiles.Where(IsImageFile))
            {
                var item = _uploadItems.FirstOrDefault(i => ReferenceEquals(i.File, file) && i.Status == FileUploadStatus.Pending);
                if (item is null) continue;
                try
                {
                    var stream = file.OpenReadStream(MaxFileSize);
                    using var ms = new MemoryStream();
                    await stream.CopyToAsync(ms);
                    _thumbnailUrls[item.Id] = $"data:{file.ContentType};base64,{Convert.ToBase64String(ms.ToArray())}";
                }
                catch { /* skip failed thumbnails */ }
            }
        }

        await OnFilesSelected.InvokeAsync(e);

        if (OnUpload is not null && AutoUpload && validFiles.Count > 0)
        {
            var pendingItems = _uploadItems.Where(i => i.Status == FileUploadStatus.Pending && validFiles.Contains(i.File)).ToList();
            // 2.2.3: was `_ = Task.Run(() => RunUploadsAsync(pendingItems))` which
            // hopped to the thread pool and defeated the Blazor sync context —
            // every StateHasChanged inside RunUploadsAsync then had to marshal
            // back via InvokeAsync. Use InvokeAsync directly to stay on the
            // sync context, with explicit exception swallowing so an unobserved
            // task exception can't crash the circuit.
            _ = InvokeAsync(async () =>
            {
                try { await RunUploadsAsync(pendingItems); }
                catch (Exception ex)
                {
                    // Surface the failure on the per-item status so the UI
                    // can show it. RunUploadsAsync already wraps per-file
                    // errors; this catch is for unexpected systemic failures
                    // (e.g. cancellation during dispose).
                    foreach (var item in pendingItems.Where(i => i.Status == FileUploadStatus.Pending || i.Status == FileUploadStatus.Uploading))
                    {
                        item.Status = FileUploadStatus.Failed;
                        item.ErrorMessage = ex.Message;
                    }
                    StateHasChanged();
                }
            });
        }
    }

    // ── Public: start uploads manually (when AutoUpload=false) ───────────────
    public async Task StartUploadAsync()
    {
        if (OnUpload is null) return;
        var pending = _uploadItems.Where(i => i.Status == FileUploadStatus.Pending).ToList();
        if (pending.Count == 0) return;
        await RunUploadsAsync(pending);
    }

    /// <summary>
    /// Clears the internal file selection and upload state, returning the component to its
    /// initial empty state. Increments an internal key to force the native file input to
    /// remount — the only cross-browser way to clear the browser's file selection so the
    /// same file can be re-picked (browsers suppress <c>onChange</c> when the same path is
    /// selected a second time without a DOM reset).
    /// In-flight uploads are cancelled before clearing.
    /// Does NOT fire <see cref="OnFilesSelected"/> or any upload callback.
    /// <para>
    /// Typical use: call via <c>@@ref</c> after processing a file in an immediate-upload
    /// flow where <see cref="ShowFileList"/> is <c>false</c> and the app renders its own
    /// list.
    /// </para>
    /// </summary>
    public async Task Reset()
    {
        foreach (var cts in _cancellations.Values.ToList())
        {
            try { cts.Cancel(); } catch (ObjectDisposedException) { }
        }
        _cancellations.Clear();
        _uploadItems.Clear();
        _thumbnailUrls.Clear();
        _thumbnailUrl = null;
        _globalErrorMessage = null;
        _allUploadedFired = false;
        _inputFileKey++;
        await InvokeAsync(StateHasChanged);
    }

    // ── Retry a single failed item ───────────────────────────────────────────
    private async Task RetryItemAsync(FileUploadItem item)
    {
        if (OnUpload is null) return;
        // Validation rejections (size/type/count) are not retryable — re-running
        // the upload would just re-violate the same constraint. The Retry button is
        // already hidden for these, but guard here too in case retry is reached via
        // a custom FileTemplate.
        if (item.IsValidationRejection) return;
        item.Status = FileUploadStatus.Pending;
        item.ErrorMessage = null;
        item.ProgressPercent = 0;
        // Re-queuing work re-arms the all-done callback for this new round.
        _allUploadedFired = false;
        await InvokeAsync(StateHasChanged);
        await RunUploadsAsync(new[] { item });
    }

    // ── Remove / cancel item ─────────────────────────────────────────────────
    private async Task RemoveItemAsync(FileUploadItem item)
    {
        if (item.Status == FileUploadStatus.Uploading)
        {
            if (_cancellations.TryGetValue(item.Id, out var cts))
            {
                cts.Cancel();
                _cancellations.Remove(item.Id);
            }
        }
        _uploadItems.Remove(item);
        _thumbnailUrls.Remove(item.Id);
        await OnFileRemoved.InvokeAsync(item);
    }

    private async Task CancelItemAsync(FileUploadItem item)
    {
        if (_cancellations.TryGetValue(item.Id, out var cts))
        {
            cts.Cancel();
            _cancellations.Remove(item.Id);
        }
        item.Status = FileUploadStatus.Cancelled;
        await InvokeAsync(StateHasChanged);
    }

    // ── Upload orchestrator ───────────────────────────────────────────────────
    private async Task RunUploadsAsync(IEnumerable<FileUploadItem> items)
    {
        // Build the concurrency gate on first use, and rebuild it when
        // MaxConcurrentUploads changed at runtime. SemaphoreSlim's capacity is fixed
        // at construction, so a latched `??=` would silently ignore the new value.
        // It is only safe to swap the instance while nothing is holding/waiting on
        // it, i.e. when no item is currently Uploading (the items in this batch have
        // not started yet at this point).
        var desiredConcurrency = Math.Max(1, MaxConcurrentUploads);
        var noUploadsInFlight = _uploadItems.All(i => i.Status != FileUploadStatus.Uploading);
        if (_concurrencySemaphore is null ||
            (noUploadsInFlight && _concurrencySemaphoreCount != desiredConcurrency))
        {
            _concurrencySemaphore?.Dispose();
            _concurrencySemaphore = new SemaphoreSlim(desiredConcurrency, desiredConcurrency);
            _concurrencySemaphoreCount = desiredConcurrency;
        }

        // Bump the batch counter so per-item rendering can still tell which batch
        // is current if it needs to (kept for back-compat / diagnostics).
        ++_currentBatchId;

        var tasks = items.Select(item => UploadOneAsync(item)).ToList();
        await Task.WhenAll(tasks);

        // Terminal check is decoupled from the batch id: when two selection
        // batches overlap, the FIRST batch to finish must not pre-empt the
        // others, and the LAST batch to finish must still be able to fire even
        // though _currentBatchId has since advanced. We therefore re-evaluate the
        // global terminal state after EVERY batch completes and fire exactly once
        // per round of pending work (_allUploadedFired is reset whenever a new
        // pending item is queued).
        await MaybeFireAllUploadedAsync();
    }

    // Fires OnAllUploaded iff every item is in a terminal state and we haven't
    // already fired for the current completed set. Safe to call from any batch.
    private async Task MaybeFireAllUploadedAsync()
    {
        if (_allUploadedFired) return;
        if (_uploadItems.Count == 0) return;
        if (!_uploadItems.All(i => i.Status is FileUploadStatus.Succeeded or FileUploadStatus.Failed or FileUploadStatus.Cancelled))
            return;

        _allUploadedFired = true;
        // This runs after Task.WhenAll on the upload batch, which can complete
        // after the component was disposed. When torn down, raise OnAllUploaded
        // directly (consumers still observe completion) but skip the render
        // dispatch that would throw on a disposed renderer.
        if (_disposed)
        {
            await OnAllUploaded.InvokeAsync(_uploadItems.AsReadOnly());
            return;
        }
        await InvokeAsync(async () =>
        {
            await OnAllUploaded.InvokeAsync(_uploadItems.AsReadOnly());
            StateHasChanged();
        });
    }

    private async Task UploadOneAsync(FileUploadItem item)
    {
        // Pass _disposeCts.Token so a task waiting for a concurrency slot is
        // woken with OperationCanceledException during disposal — not left
        // hanging or hit with ObjectDisposedException. If WaitAsync throws we
        // never acquired the slot, so we mark the item Cancelled and return
        // immediately: no Release() call, no over-release.
        try
        {
            await _concurrencySemaphore!.WaitAsync(_disposeCts.Token);
        }
        catch (OperationCanceledException)
        {
            item.Status = FileUploadStatus.Cancelled;
            return;
        }
        // Semaphore slot acquired — Release() in the finally below is guaranteed
        // to run once and only once for this acquisition.
        try
        {
            var cts = new CancellationTokenSource();
            _cancellations[item.Id] = cts;

            item.Status = FileUploadStatus.Uploading;
            item.ProgressPercent = 0;
            await InvokeAsync(StateHasChanged);

            var progress = new Progress<int>(pct =>
            {
                item.ProgressPercent = Math.Clamp(pct, 0, 100);
                // Fire-and-forget render. Guarded against a disposed renderer:
                // the consumer's OnUpload Task can keep reporting progress after
                // the component is gone, which would otherwise throw
                // ObjectDisposedException on the dispatch.
                _ = SafeInvokeStateHasChangedAsync();
            });

            try
            {
                var url = await OnUpload!(item, progress, cts.Token);
                if (cts.Token.IsCancellationRequested)
                {
                    item.Status = FileUploadStatus.Cancelled;
                }
                else
                {
                    item.Status = FileUploadStatus.Succeeded;
                    item.ProgressPercent = 100;
                    item.Url = url;
                    // The await above (OnUpload) can complete after the component
                    // was disposed; don't dispatch a render onto a torn-down
                    // renderer. The OnFileUploaded callback is still raised
                    // directly so consumers observe the result regardless.
                    if (!_disposed)
                    {
                        await InvokeAsync(async () =>
                        {
                            await OnFileUploaded.InvokeAsync(item);
                            StateHasChanged();
                        });
                    }
                    else
                    {
                        await OnFileUploaded.InvokeAsync(item);
                    }
                }
            }
            catch (OperationCanceledException)
            {
                item.Status = FileUploadStatus.Cancelled;
            }
            catch (Exception ex)
            {
                item.Status = FileUploadStatus.Failed;
                item.ErrorMessage = ex.Message;
                // OnUpload threw, possibly after the component was disposed (e.g.
                // the upload was cancelled by DisposeAsync). Skip the render
                // dispatch when torn down but still raise OnFileFailed.
                if (!_disposed)
                {
                    await InvokeAsync(async () =>
                    {
                        await OnFileFailed.InvokeAsync(item);
                        StateHasChanged();
                    });
                }
                else
                {
                    await OnFileFailed.InvokeAsync(item);
                }
            }
            finally
            {
                _cancellations.Remove(item.Id);
                try { cts.Dispose(); } catch (ObjectDisposedException) { }
            }
        }
        finally
        {
            // Release always runs here because WaitAsync succeeded (the early-return
            // path above handles the cancelled-before-acquire case). Null-guard is
            // kept for the RunUploadsAsync hot-swap path where a MaxConcurrentUploads
            // change can replace the instance while this task is in-flight.
            _concurrencySemaphore?.Release();
            await SafeInvokeStateHasChangedAsync();
        }
    }

    // ── Dispose ──────────────────────────────────────────────────────────────
    public async ValueTask DisposeAsync()
    {
        // Mark disposed FIRST so any in-flight upload pipeline callbacks
        // (progress reports, success/fail handlers, the terminal all-uploaded
        // check) that fire after teardown short-circuit their render dispatch
        // instead of calling InvokeAsync(StateHasChanged) on a disposed renderer.
        _disposed = true;

        // Cancel pending WaitAsync calls BEFORE touching per-file tokens.
        // Any UploadOneAsync task blocked waiting for a semaphore slot will
        // receive OperationCanceledException, mark the item Cancelled, and
        // return WITHOUT calling Release() — so no slot is over-released and
        // the semaphore is never accessed after this point by those tasks.
        _disposeCts.Cancel();

        // Cancel + dispose all per-file in-flight upload tokens so running
        // OnUpload handlers observe cancellation and unwind cleanly.
        foreach (var cts in _cancellations.Values.ToList())
        {
            try { cts.Cancel(); } catch (ObjectDisposedException) { }
            cts.Dispose();
        }
        _cancellations.Clear();

        // Do NOT dispose _concurrencySemaphore here. Tasks that already passed
        // WaitAsync still hold a slot and will call Release() in their finally
        // block; disposing the semaphore before those Release() calls completes
        // would throw ObjectDisposedException. SemaphoreSlim backed by a .NET
        // Monitor (no unmanaged wait handle) is safe to leave for the GC —
        // its finalizer is a no-op in that configuration.
        _disposeCts.Dispose();
        await Task.CompletedTask;
    }

    // An icon action button (Cancel/Retry/Remove) wrapped in the Lumeo <Tooltip> with
    // an explicit aria-label for the accessible name — replaces the native title.
    private RenderFragment IconActionButton(string cls, string label, Lumeo.IconSource icon, Microsoft.AspNetCore.Components.EventCallback onClick) => b =>
    {
        b.OpenComponent<Tooltip>(0);
        b.AddAttribute(1, "ChildContent", (RenderFragment)(tip =>
        {
            tip.OpenComponent<TooltipTrigger>(0);
            tip.AddAttribute(1, "AsChild", true);
            tip.AddAttribute(2, "ChildContentSlot", (RenderFragment<Lumeo.TriggerSlot>)(slot => sb =>
            {
                sb.OpenElement(0, "button");
                sb.AddAttribute(1, "type", "button");
                sb.AddAttribute(2, "class", cls);
                sb.AddAttribute(3, "aria-label", label);
                sb.AddAttribute(4, "onclick", onClick);
                sb.AddMultipleAttributes(5, slot.Attributes);
                sb.OpenComponent<SvgGlyph>(6);
                sb.AddAttribute(7, "Svg", icon);
                sb.AddAttribute(8, "class", "h-3.5 w-3.5");
                sb.CloseComponent();
                sb.CloseElement();
            }));
            tip.CloseComponent();

            tip.OpenComponent<TooltipContent>(3);
            tip.AddAttribute(4, "ChildContent", (RenderFragment)(cb => cb.AddContent(0, label)));
            tip.CloseComponent();
        }));
        b.CloseComponent();
    };

    // ── Per-file row renderer ────────────────────────────────────────────────
    private RenderFragment RenderFileItem(FileUploadItem item) => builder =>
    {
        // Outer row
        builder.OpenElement(0, "div");
        builder.AddAttribute(1, "class", "flex flex-col gap-1.5 rounded-md border border-border/40 bg-muted/30 p-2");

        // Top row: icon + name + size + action buttons
        builder.OpenElement(2, "div");
        builder.AddAttribute(3, "class", "flex items-center gap-2");

        // File icon or thumbnail
        if (ShowThumbnails && IsImageFile(item.File) && _thumbnailUrls.TryGetValue(item.Id, out var thumb))
        {
            builder.OpenElement(4, "div");
            builder.AddAttribute(5, "class", "h-8 w-8 shrink-0 overflow-hidden rounded bg-muted");
            builder.OpenElement(6, "img");
            builder.AddAttribute(7, "src", thumb);
            builder.AddAttribute(8, "alt", item.Name);
            builder.AddAttribute(9, "class", "h-full w-full object-cover");
            builder.CloseElement(); // img
            builder.CloseElement(); // div
        }
        else
        {
            builder.OpenComponent<SvgGlyph>(10);
            builder.AddAttribute(11, "Svg", LumeoIcons.File);
            builder.AddAttribute(12, "class", item.Status == FileUploadStatus.Failed ? "h-4 w-4 shrink-0 text-destructive" : "h-4 w-4 shrink-0 text-muted-foreground");
            builder.CloseComponent();
        }

        // Name + size
        builder.OpenElement(13, "div");
        builder.AddAttribute(14, "class", "flex-1 min-w-0");
        builder.OpenElement(15, "p");
        builder.AddAttribute(16, "class", "text-sm font-medium truncate");
        builder.AddContent(17, item.Name);
        builder.CloseElement(); // p
        builder.OpenElement(18, "p");
        builder.AddAttribute(19, "class", "text-xs text-muted-foreground");
        builder.AddContent(20, FormatSize(item.Size));
        builder.CloseElement(); // p
        builder.CloseElement(); // div name+size

        // Status icon
        if (item.Status == FileUploadStatus.Succeeded)
        {
            builder.OpenComponent<SvgGlyph>(21);
            builder.AddAttribute(22, "Svg", LumeoIcons.Check);
            builder.AddAttribute(23, "class", "h-4 w-4 shrink-0 text-success");
            builder.CloseComponent();
        }
        else if (item.Status == FileUploadStatus.Failed)
        {
            builder.OpenComponent<SvgGlyph>(24);
            builder.AddAttribute(25, "Svg", LumeoIcons.CircleX);
            builder.AddAttribute(26, "class", "h-4 w-4 shrink-0 text-destructive");
            builder.CloseComponent();
        }

        // Action buttons
        if (item.Status == FileUploadStatus.Uploading)
        {
            // Cancel button (Lumeo <Tooltip>, not native title)
            builder.AddContent(27, IconActionButton(
                "inline-flex items-center justify-center h-6 w-6 rounded text-muted-foreground hover:text-destructive transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1",
                "Cancel", LumeoIcons.X,
                Microsoft.AspNetCore.Components.EventCallback.Factory.Create(this, () => CancelItemAsync(item))));
        }
        else if (item.Status == FileUploadStatus.Failed && OnUpload is not null && !item.IsValidationRejection)
        {
            // Retry button (only for upload failures, not validation rejections).
            // Gated on the IsValidationRejection discriminator rather than matching
            // English substrings in ErrorMessage, which broke for localized text and
            // custom MaxFileSizeError/FileTypeError/MaxFilesError overrides.
            builder.AddContent(35, IconActionButton(
                "inline-flex items-center justify-center h-6 w-6 rounded text-muted-foreground hover:text-primary transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1",
                "Retry", LumeoIcons.RotateCcw,
                Microsoft.AspNetCore.Components.EventCallback.Factory.Create(this, () => RetryItemAsync(item))));
        }
        else if (item.Status != FileUploadStatus.Uploading)
        {
            // Remove button (Lumeo <Tooltip>, not native title)
            builder.AddContent(43, IconActionButton(
                "inline-flex items-center justify-center h-6 w-6 rounded text-muted-foreground hover:text-destructive transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1",
                "Remove", LumeoIcons.X,
                Microsoft.AspNetCore.Components.EventCallback.Factory.Create(this, () => RemoveItemAsync(item))));
        }

        builder.CloseElement(); // div top row

        // Progress bar (when uploading or showing progress for succeeded)
        if (item.Status == FileUploadStatus.Uploading || (item.Status == FileUploadStatus.Succeeded && item.ProgressPercent > 0))
        {
            builder.OpenElement(51, "div");
            builder.AddAttribute(52, "class", "h-1.5 w-full overflow-hidden rounded-[calc(var(--radius)*2)] bg-muted");
            builder.OpenElement(53, "div");
            var pct = Math.Clamp(item.ProgressPercent, 0, 100);
            var color = item.Status == FileUploadStatus.Succeeded ? "bg-success" : "bg-primary";
            builder.AddAttribute(54, "class", $"h-full rounded-[calc(var(--radius)*2)] {color} transition-all duration-300");
            builder.AddAttribute(55, "style", $"width: {pct}%");
            builder.CloseElement(); // inner div
            builder.CloseElement(); // outer div
        }

        // Error message
        if (item.Status == FileUploadStatus.Failed && item.ErrorMessage is not null)
        {
            builder.OpenElement(56, "p");
            builder.AddAttribute(57, "class", "text-xs text-destructive");
            builder.AddContent(58, item.ErrorMessage);
            builder.CloseElement(); // p
        }

        builder.CloseElement(); // outer row div
    };

    // ── Helpers ──────────────────────────────────────────────────────────────
    private bool IsImageFile(IBrowserFile file) =>
        file.ContentType.StartsWith("image/", StringComparison.OrdinalIgnoreCase);

    private string? GetThumbnailUrl(FileUploadItem item) =>
        _thumbnailUrls.TryGetValue(item.Id, out var url) ? url : null;

    private static bool IsAccepted(IBrowserFile file, string accept)
    {
        var tokens = accept.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
        foreach (var token in tokens)
        {
            if (token.StartsWith('.'))
            {
                if (file.Name.EndsWith(token, StringComparison.OrdinalIgnoreCase)) return true;
            }
            else if (token.EndsWith("/*"))
            {
                var prefix = token[..^1]; // e.g. "image/"
                if (file.ContentType.StartsWith(prefix, StringComparison.OrdinalIgnoreCase)) return true;
            }
            else
            {
                if (string.Equals(file.ContentType, token, StringComparison.OrdinalIgnoreCase)) return true;
            }
        }
        return false;
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        if (bytes < 1024L * 1024 * 1024) return $"{bytes / (1024.0 * 1024.0):F1} MB";
        return $"{bytes / (1024.0 * 1024.0 * 1024.0):F1} GB";
    }
